import java.util.Scanner;

public class SecureBufferInput {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Initialize a fixed-size buffer with proper bounds
        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        // Limit the number of characters copied to the buffer
        int charsToCopy = Math.min(userInput.length(), bufferSize);
        userInput.getChars(0, charsToCopy, buffer, 0);

        System.out.println("Buffer content: " + new String(buffer));
    }
}

